/* {{pp-template|small=yes}} */
div.template-markup-wrapper > :first-child {
	margin-top: 0;
}

div.template-markup-wrapper > :last-child {
	margin-bottom: 0;
}

.template-markup {
	margin:0;
	border:none;
	word-wrap:break-word;
	white-space:pre-wrap;	
}

code.template-markup {
	padding:0;
}

pre.template-markup {
	padding:2px 0 0;
}

